var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"좋아. 이걸로 한 마리 더 잡았네.","JPN":"よし、これで1匹追加ね。","ENG":"Good. That's one more down.","TWN":"太棒了，又消滅了一隻。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"대단해! 역시 우리 소대장이야!","JPN":"すごい！　さすが小隊長！","ENG":"That was amazing! You're the best, Commander!","TWN":"真厲害！不愧是我們的小隊長！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"나, 나도 동감이야. 미나는 정말 실력이 대단하구나......","JPN":"ど、同感だよ。ミナは本当に強いんだね……","ENG":"I-I agree. You're very impressive, Mina...","TWN":"我、我也同意。米娜的實力真強……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"잠시 실례할게요. 여기가 미나 소대인가요?","JPN":"あの、失礼します。ミナ小隊ですか？","ENG":"Excuse me. Is this the Mina Squad?","TWN":"打擾一下，這裡是米娜小隊嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아, 회장님! 제대로 찾아 오셨어요!","JPN":"あっ、会長！　はい、こちらです！","ENG":"Oh, Ms. President! It sure is!","TWN":"啊，會長！你來了！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아니야! 그 이름으로 부르지 말라고 했잖아!","JPN":"ねえ、その呼び方は勘弁して？","ENG":"No, it's not! I told you to stop calling us that name!","TWN":"喂！都說不要用那個名稱了！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어......? 학생회장?","JPN":"あれ……？　生徒会長？","ENG":"Huh? YOU'RE the Student President?","TWN":"呃……？學生會長？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"역시, 이름이 익숙하다고 생각했는데 블루로즈 섬에서 만났던 분이군요.","JPN":"やはり。聞き覚えのある名前だと思ったら、ブルーローズ島でお会いした方ですね。","ENG":"No wonder the name sounded familiar. We once met on Blue Rose Island.","TWN":"果然，就覺得名字有些熟悉，原來是在藍玫瑰島見過的人。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"나이에 어울리지 않게 대단한 실력이라고 생각했는데, 아카데미에서 다시 만나다니 기쁘네요.  ","JPN":"その年齢にしてはすごい実力だと思いましたが、アカデミーでまたお会いできて嬉しいです。 ","ENG":"I was impressed by how capable you are at your age. It's great to see you again at the Academy.  ","TWN":"當時就覺得你實力不簡單，能在學院再次見面我很高興。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으응, 그렇지. 뭐. 그때는 갑판 청소부 신세였지만.","JPN":"あ、まあね。あの時はただの甲板掃除担当だったけどね。","ENG":"Yeah, I guess. Thanks. Then again, I was just a deck janitor back then.","TWN":"嗯。當時我只是充當甲板清道夫而已。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그런데 저희한테는 무슨 일이세요, 회장님?","JPN":"ところで、私たちに何かご用ですか、会長？","ENG":"How may we help you, Ms. President?","TWN":"你來找我們有什麼事，會長？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"다른 학생들에게서 들어오는 항의를 해결하러 왔어요.","JPN":"他の生徒から苦情を受けて話に参りました。","ENG":"I've come to sort out a complaint lodged by other students.","TWN":"我是來解決其他學生提出的抗議的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"여러분이 침식체를 너무 많이 격퇴하는 바람에 다른 학생들이 훈련을 진행하지 못하는 상태라더군요.","JPN":"皆さんがこの辺の侵食体を倒しすぎて、他の生徒の訓練が進まない状況らしいです。","ENG":"They're saying they cannot train because your squad has been killing all the C.O.s.","TWN":"因為三位消滅的侵蝕體太多，其他學生現在沒辦法進行訓練了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"회장님, 그게 무슨 말씀이세요!","JPN":"会長、それは理不尽です！","ENG":"But that's absurd!","TWN":"會長，你怎麼可以這麼說呢！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"훈련도 마술도 최선을 다하지 않으면 안 되는 법이잖아요!","JPN":"訓練もマジックも最善を尽くしてやらなければならないでしょう？","ENG":"We should always try our best, whether it's training or magic tricks!","TWN":"訓練也好，魔術也好，都要盡全力才行啊！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"틀린 말은 아니지만, 학생들에게 공평한 기회를 주는 것 역시 학생회장의 본분이에요.","JPN":"間違ってはいませんが、生徒に公平な機会を与えることも生徒会長の本分です。","ENG":"I don't disagree, but as Student President, I'm also responsible for giving everyone a fair shot.","TWN":"你說的沒錯，但是我也得給其他學生公平的機會，這也是學生會長的本職工作。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"미카도 제 마음을 이해해 주면 좋겠어요.","JPN":"ミカさんもどうかご理解いただけると幸いです。","ENG":"I hope you can understand, Mika.","TWN":"我希望米卡你也能理解我的心情。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그, 그건 그렇지만요......","JPN":"そ、それはそうですけど……","ENG":"B-but still...","TWN":"但、但是……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"미카 쟤, 회장 앞에선 꽤 얌전해지네.","JPN":"ミカって会長の前ではかなり大人しいね。","ENG":"Mika's so docile in front of the President.","TWN":"米卡在會長面前變得乖巧了呢。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"맞아. 미카의 마술을 진지하게 평가해 주는 사람은 학생회에서 회장님밖에 없거든.","JPN":"うん。ミカのマジックを真面目に評価してるのは生徒会の中でも会長しかいないからね。","ENG":"She sure is. It's because the President is the only one who takes her magic tricks seriously.","TWN":"對啊。因為在學生會裡只有會長會認真評價米卡的魔術。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그래도 회장님, 지금 점수를 안 따면 레이 선배는 올해도 졸업을 하지 못 할 거에요.","JPN":"でも会長、今のうちに点数を稼いでおかないとレイ先輩は今年も卒業できません。","ENG":"Still, Ray won't be able to graduate again this year if we don't get these points.","TWN":"可是會長，如果現在不得分的話，雷伊前輩今年也沒辦法畢業啊。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그 일이라면 걱정 마세요. 실은 방금 전 여러분이 싸우는 모습을 지켜보고 있었거든요.","JPN":"その件なら心配いりません。実は、さっき皆さんが戦う姿をしばらく見せてもらっていました。","ENG":"Don't worry about that. I've been watching you in action, actually.","TWN":"如果是因為這個，你不用擔心。我剛才在一旁看到了你們戰鬥的樣子。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"유미나 학생은 물론이고, 레이 학생도 방법만 독특할 뿐 다른 사람을 지키기에 나무랄 데 없는 실력이었어요.","JPN":"ヤナギ・ミナさんはもちろん、レイさんもやり方が変わっているだけで他の人を守るには申し分のない実力でした。","ENG":"Not only Mina, but also Ray seems to be quite capable of protecting others with his unique skills.","TWN":"不說劉米娜同學，雷伊同學也僅僅只是方法比較獨特而已，已經充分擁有保護他人的實力了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"다만 미카는 조금 더 분발해야겠더군요.","JPN":"ただ、ミカさんはもう少し頑張らないとですね。","ENG":"As for you, Mika, I think you could do a little better.","TWN":"只有米卡同學需要更加努力一點才行。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"우으......","JPN":"うう……","ENG":"Aw...","TWN":"嗚哇……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이미 얻은 점수도 충분한 만큼, 학생회장의 권한으로 최고 점수를 드리기로 하죠.","JPN":"すでに十分な点数を稼いでいるので、生徒会長の権限で最高点数を付与します。","ENG":"Since you've already accumulated a sufficient amount of points, I'll use my authority as Student President to grant you the maximum amount.","TWN":"你們的分數已經足夠多了，我可以用學生會長的許可權給與你們最高分數。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그러니 지금부터는 다른 학생들과의 조화로운 성장을 위해, 잠시 자리를 비켜 주시길.","JPN":"ですので、これからは他の生徒たちとの調和のとれた成長のため、しばらくお休みいただけると助かります。","ENG":"So please, stand down for the sake of ensuring a balanced training experience for all students here.","TWN":"所以現在開始，為了其他學生也能順利進行成長，請你們讓出位子吧。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"등수가 정해졌으면 상관없지, 뭐. 나도 조금 피곤하긴 하고.","JPN":"順位が決まったなら構わないよ。私もちょっと疲れてきたし。","ENG":"Well, if we're already in first place, I don't see why not. I was getting a bit tired anyway.","TWN":"既然排名已定，那我就無所謂了。本來就已經有些累了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이해해 줘서 고마워요.","JPN":"ご理解いただきありがとうございます。","ENG":"Thank you for your understanding.","TWN":"感謝你的理解。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그러면 저와 함께 가죠. 숨을 고르는 동안 제가 엄선한 전통차를 대접하도록 할게요.","JPN":"それでは、私と一緒に行きましょう。一息つく間、厳選したお茶をご馳走しますね。","ENG":"Why don't you join me now? While you catch your breath, I'd like to treat you to a hand-picked selection of traditional tea.","TWN":"那現在就跟我走吧。在休息期間用我嚴選的傳統茶葉來招待你們。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"으엑...... 그거 총학생회 회의 때마다 나오는 엄청 쓴 음료수 아니에요?","JPN":"ええっ……それって、生徒会の会議の時に出てくるすごく苦いお茶ですよね？","ENG":"Eww... Isn't that the super bitter drink they serve at every Student Council Meeting?","TWN":"呃……是那個每次學生會開會的時候都會發的超苦飲料嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"오해하지 마세요, 미카.","JPN":"誤解しないでください、ミカさん。","ENG":"There's more to tea than taste, Mika.","TWN":"別誤會，米卡。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"차는 마음을 비추는 거울입니다. 마음이 평화로우면 그 안의 그윽한 맛도 느낄 수 있죠.","JPN":"お茶は心を映す鏡のようなものです。心が穏やかなら、その中の奥ゆかしい味も感じられるでしょう。","ENG":"A cup of tea is like a mirror of the mind. If your mind is at peace, you will be able to enjoy the subtle fragrance within.","TWN":"茶是照亮心靈的鏡子。只要心態平和就能感受到其中的濃郁味道。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐야, 방금 저 소리는?","JPN":"今の音はなに？","ENG":"What was that just now?","TWN":"咦，剛才是什麼聲音？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"어떤 놈이야! 당장 나와! 잡히면 가만 안 둬!","JPN":"誰だ！　今すぐ出てこい！　こんな真似してタダじゃ済まないから！","ENG":"Who did this? You'd better fess up! You'll be sorry if I catch you!","TWN":"到底是誰！快滾出來！被我抓到就死定了！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이디스, 무슨 일이죠?","JPN":"イーディス、どうしましたか？","ENG":"What's wrong, Edith?","TWN":"伊蒂絲，出了什麼事？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"간덩이가 배 밖으로 나온 어떤 자식이 내가 만든 자율 방어 시스템을 망가트렸다고!","JPN":"誰だか知らないけど、私が作った自律防御システムを壊したんだよぉ！","ENG":"Some reckless fool broke my ADS!","TWN":"不知道是哪個膽大包天的傢伙破壞了我的自主防禦系統。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L11_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"게다가 처음 보는 해킹 방식이야...... 기술보다는 카운터 능력에 더 가까워.","JPN":"しかも初めてみるハッキング方法で……技術っていうかカウンター能力に近い。","ENG":"I've never seen a hacking technique like this... It's more like a Counter ability than actual technology.","TWN":"這是我第一次見到的破解方式……與其說是技術，倒不如說更像是制裁者的特殊能力。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"무슨 수작을 부렸는지 잡아다가 아주 열띤 토론을 벌이고 싶단 말이야!","JPN":"捕まえたら何をしてくれたのか、徹夜で説教して言い訳を聞かせてもらいたいくらいだよぉ！","ENG":"I'm going to catch whoever did this so I can have a passionate discussion about debugging my tech!","TWN":"我一定要抓到他，問問他到底搞了什麼鬼！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"잠시만요. 지금 그 말...... 자율 방어 시스템이 정지했다는 뜻인가요?","JPN":"待ってください、今の話……つまり自律防御システムが停止したということですか？","ENG":"Hang on. Are you saying... The defense system is not operational right now?","TWN":"等等。你現在的意思是……自主防禦系統停止運行了？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"응? 그런데 왜?","JPN":"そうだよぉ？　でもなんで？","ENG":"Huh? Why do you ask?","TWN":"是啊？怎麼了？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"비상 상황입니다. 즉시 훈련을 중지하고 학생들을 대피시켜야 해요.","JPN":"非常事態です。ただちに訓練を中止して生徒たちを避難させなければなりません。","ENG":"This is an emergency. We must abort the training mission at once and evacuate the students.","TWN":"緊急情況。請立即停止訓練，轉移學生。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"흠냐, 그럴 필요까지 없잖아.","JPN":"むにゃ、そこまでする必要はなくない？","ENG":"Meh, is that really necessary?","TWN":"喂，沒有必要這樣吧。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"어차피 시스템은 금방 고쳐질 테고, 근처에 있던 침식체들은 모두 정리했다던데?","JPN":"どうせシステムはすぐ直せるし、近くにいる侵食体も管理局が片付けたんでしょー？","ENG":"ADS will be back online soon enough, and they cleared out all the dangerous C.O.s already, didn't they?","TWN":"反正系統馬上就能修復，附近的侵蝕體也早就被清理掉了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이 곳도 엄연한 이면세계입니다. 조금의 예외도 소홀히 넘어가선......","JPN":"一応裏世界です。少しの例外もないがしろにしてはいけません。","ENG":"We are still on the Counterside. We must remain vigilant regardless—","TWN":"這裡畢竟是異界，不能有半分疏忽……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"AI_ACADEMY_SHIP_NULL","text":{"KOREA":"<color=#ffd34c>침식파 경보.</color>","JPN":"<color=#ffd34c>侵食波警告。</color>","ENG":"<color=#ffd34c>CORRUPTION RAY ALERT.</color>","TWN":"<color=#ffd34c>侵蝕波警報。</color>"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L22_1","type":"dialog","speaker":"AI_ACADEMY_SHIP_NULL","text":{"KOREA":"<color=#ffd34c>훈련 장소 외곽에서 대규모 침식체 무리가 접근 중.</color>","JPN":"<color=#ffd34c>訓練場所の外郭から大規模侵食体の群れが接近中。</color>","ENG":"<color=#ffd34c>A group of C.O.s is approaching the training area perimeter.</color>","TWN":"<color=#ffd34c>訓練場週邊有大規模侵蝕體正在靠近</color>"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"뭐어? 정말 침식체가 쳐들어 온다고?!","JPN":"なに？　本当に侵食体が押しかけてくるって！？","ENG":"What? They're really coming?","TWN":"什麼? 真的有侵蝕體？！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"......아무래도 기우가 아니었나 보군요.","JPN":"……どうやら杞憂ではなかったようですね。","ENG":"Looks like my concerns weren't unfounded.","TWN":"……看來這不是偶然。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"유미나 학생!","JPN":"ヤナギ・ミナさん！","ENG":"Mina!","TWN":"劉米娜同學！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응?","JPN":"ん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"말을 번복해서 미안하지만, 차를 대접하는 시간은 뒤로 미뤄야겠어요.","JPN":"誘った身として申し訳ありませんが、お茶の時間は今度にさせていただきますね。","ENG":"I hate to go back on my word, but I'll have to defer our tea time.","TWN":"很抱歉，只能下次再請你喝茶了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"저는 지금부터 학생들이 대피할 때까지 침식체들을 막을 생각입니다.","JPN":"私は今から生徒たちが避難するまで、侵食体を食い止めます。","ENG":"I'm going to hold off the C.O.s until the students can evacuate.","TWN":"我需要抵禦侵蝕體的進攻直到學生們全部安全轉移。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"괜찮다면 저와 함께 해 주시겠어요?","JPN":"よろしければ、私と一緒に戦ってくれませんか？","ENG":"Would you mind joining me?","TWN":"你願意與我一起戰鬥嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"실전 경험이 풍부한 분이 함께라면 큰 힘이 될 겁니다.","JPN":"実戦経験が豊富な方がご一緒ならとても心強いと思います。","ENG":"Given your extensive combat experience, I'm sure you'll prove most helpful.","TWN":"你實戰經驗豐富，會對我們有很大幫助。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"무리할 필요는 없어요. 곧 선생님들이 계시는 본대에서 지원 부대를 보낼 테니까요.","JPN":"無理する必要はありません。まもなく先生たちがいる本隊から応援部隊が送られてくるでしょう。","ENG":"I'm not asking you to push yourself too hard. The faculty's main camp will soon send reinforcements.","TWN":"不用太擔心。老師們所在的營地很快就會派部隊過來支援。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그림자의 출몰에 대비한 전력이니 진압은 문제없을 겁니다. 그 때까지만 막으면 돼요.","JPN":"シャドウの出没に備えた戦力ですので、鎮圧は問題ないでしょう。その時まで足止めできればと思います。","ENG":"They should have little trouble quelling the breach as they're trained to fight Shadows. We just need to hold the line until the cavalry gets here.","TWN":"那個部隊是為了預防暗影出現準備的，有充分的實力。只要堅持到他們到來就可以了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐...... 요즘 주위에서 심심하면 일이 터지니까 이렇게 될 것 같긴 했어.","JPN":"まあ……いつもちょっと平和だなと思った矢先に何かしら事件が発生するから、こんなこともあるかと思ってはいたけどね。","ENG":"Well... I had a bad feeling about this anyway, since these days, something goes wrong all the time.","TWN":"嗯……最近經常發生事故，我有預感會變成這樣。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"다이브하기 전에 불길한 이야기도 들었거든.","JPN":"ダイブする前に不吉な話も聞いたし。","ENG":"Not to mention that ominous story I heard before the Dive.","TWN":"在躍入之前也聽到了不祥的事情。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"BATTLE_BOSS_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"마음의 준비는 예전에 끝냈으니까 부탁은 안 해도 돼.","JPN":"心の準備はとっくにできているから、そんな腰を低くして頼む必要はないよ。","ENG":"I'm already mentally prepared for this, so you don't have to convince me.","TWN":"我早就做好了心理準備，就算你不說，我也會去戰鬥。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"고마워요, 미나 양.","JPN":"ありがとうございます、ミナさん。","ENG":"Thank you, Mina.","TWN":"謝謝你，米娜。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그럼 저들에게 가르쳐 주러 가죠. 수업 시간에 행패를 부리면 어떻게 되는지.","JPN":"それでは、彼らに教えてやりましょう。授業を邪魔したらどうなるのかを。","ENG":"Then let's go teach them a lesson... about what happens to those who dare to interrupt a class in session.","TWN":"那麼我們就去教訓那些侵蝕體吧。讓它們知道在上課的時候搗亂會有什麼下場。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};